using UnityEngine;
using Climbing;

public class AirInspector
{
    public static string Run()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "No player found in scene.";

        GameObject pm = cc.gameObject;
        Animator anim = pm.GetComponent<Animator>();
        Rigidbody rb = pm.GetComponent<Rigidbody>();
        CapsuleCollider col = pm.GetComponent<CapsuleCollider>();
        ThirdPersonController tpc = pm.GetComponent<ThirdPersonController>();

        string report = $"--- Player Air Inspection: {pm.name} ---\n";
        if (anim != null) report += $"Animator: ApplyRootMotion={anim.applyRootMotion}\n";
        if (rb != null) report += $"Rigidbody: Gravity={rb.useGravity}, Kinematic={rb.isKinematic}, Drag={rb.drag}\n";
        if (col != null) report += $"Capsule: Center={col.center}, Height={col.height}, Radius={col.radius}, IsTrigger={col.isTrigger}\n";
        if (tpc != null) report += $"TPC: Grounded={tpc.isGrounded}, onAir={tpc.onAir}, isJumping={tpc.isJumping}\n";

        return report;
    }
}
